// lib/utils/sail_logo.dart
// SAIL logo embedded as base64 PNG — no network dependency
// Usage: Image.memory(SailLogo.bytes, width: 48, height: 48)
//        or use SailLogo.widget(size: 48)

import 'dart:convert';
import 'dart:typed_data';
import 'package:flutter/material.dart';

class SailLogo {
  static const String _b64 = '';

  static Uint8List get bytes => base64Decode(_b64);

  /// Returns a circular SAIL logo widget.
  static Widget widget({double size = 48, Color? bgColor}) {
    return Container(
      width: size, height: size,
      decoration: BoxDecoration(
        shape: BoxShape.circle,
        color: bgColor ?? Colors.white,
        boxShadow: [BoxShadow(
          color: Colors.black.withOpacity(0.12),
          blurRadius: 8, offset: const Offset(0, 2))],
      ),
      child: ClipOval(
        child: Image.memory(
          bytes,
          width: size, height: size,
          fit: BoxFit.contain,
        ),
      ),
    );
  }

  /// Small icon version — no clip, just sized image.
  static Widget icon({double size = 32}) {
    return Image.memory(bytes, width: size, height: size, fit: BoxFit.contain);
  }
}
